    formatMaintainStatus(row) {
      if (row.status === 1) {
        return '<span style="color: #4299E1; font-weight: bold;">充电中</span>';
      } else if (row.status === 2) {
        return '<span style="color: #F56C6C; font-weight: bold;">维修中</span>';
      } else {
        return '<span style="color: #67C21A; font-weight: bold;">正常</span>';
