    // 保存配置
    async saveConfig() {
      try {
        // 表单校验
        await this.$refs.configForm.validate();

        // 调用保存接口
        const res = await request.post('/system/config/save', this.config);
        if (res.data) {
          this.$message.success('配置保存成功！');
          // 重新初始化折线图（预警阈值可能变化）
          this.initCharts();
        }
      } catch (error) {
        console.error('保存配置失败：', error);
        if (error.message) {
          this.$message.error(error.message);
        } else {
          this.$message.error('配置保存失败，请重试！');
        }
      }
    },
    // 重置配置
    resetConfig() {
      this.$refs.configForm.resetFields();
      this.$message.info('配置已重置为初始值');
    },
    // 导入配置
    importConfig() {
      // 创建文件选择器
      const input = document.createElement('input');
      input.type = 'file';
      input.accept = '.json';
      input.onchange = async e => {
        const file = e.target.files[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = async event => {
          try {
            const configData = JSON.parse(event.target.result);
            // 合并配置（避免缺失字段）
            this.config = {
              ...this.config,
              ...configData
            };
            this.$message.success('配置导入成功！');
          } catch (error) {
            this.$message.error('配置文件格式错误，请检查！');
          }
        };
        reader.readAsText(file);
      };
      input.click();
    },
    // 导出配置
    exportConfig() {
      // 将配置转为JSON字符串
      const configStr = JSON.stringify(this.config, null, 2);
      const blob = new Blob([configStr], {
        type: 'application/json'
      });

      // 创建下载链接
      const a = document.createElement('a');
      a.href = URL.createObjectURL(blob);
      a.download = `无人机系统配置_${new Date().getTime()}.json`;
      a.click();

      // 释放URL
      URL.revokeObjectURL(a.href);
      this.$message.success('配置导出成功！');
    }
