  beforeDestroy() {
    // 销毁ECharts实例，避免内存泄漏
    if (this.barChart) {
      this.barChart.dispose();
      this.barChart = null;
    }
    if (this.lineChart) {
      this.lineChart.dispose();
      this.lineChart = null;
    }
    if (this.detailChart) {
      this.detailChart.dispose();
      this.detailChart = null;
    }
    // 移除窗口resize监听
    window.removeEventListener('resize', this.resizeCharts);
